1 – Einfache Variablen
Wie du bereits gesehen hast, können Werte Variablen zugewiesen werden. Für die Zuweisung sind &lt;- und = gleichwertig:
#| '!! shinylive warning !!': |
#|   shinylive does not work in self-contained HTML documents.
#|   Please set `embed-resources: false` in your metadata.
#| standalone: true
#| viewerHeight: 220
library(shiny)
ui &lt;- fluidPage(
  textAreaInput("code", "Zuweisungen", value = "a &lt;- 2\nb &lt;- TRUE\n# oder:\nb = TRUE\nname = 'Rosalinde'", width = '100%', height = '120px'),
  actionButton("run", "Run Code", class = "btn-success"),
  verbatimTextOutput("out")
)
server &lt;- function(input, output) {
  observeEvent(input$run, {
    output$out &lt;- renderPrint({
      # Wir parsen den Code
      exprs &lt;- parse(text = input$code)
      for (e in exprs) {
        # withVisible gibt eine Liste zurück: 
        # $value ist das Ergebnis, $visible ist TRUE oder FALSE
        res &lt;- withVisible(eval(e))

        # Nur drucken, wenn das Ergebnis nicht NULL ist UND sichtbar sein soll
        if (!is.null(res$value) && res$visible) {
          print(res$value)
        }
      }
    })
  })
}
shinyApp(ui, server)
