  textAreaInput("code", "Vektoren erstellen", value = "x &lt;- 9\nlength(x)       # x ist ein Vektor der Länge 1\n\ny &lt;- c(x, 3, 7, 2)\nlength(y)       # y ist ein Vektor der Länge 4", width = '100%', height = '130px'),
  actionButton("run", "Run Code", class = "btn-success"),
  verbatimTextOutput("out")
)
server &lt;- function(input, output) {
  observeEvent(input$run, {
