ui &lt;- fluidPage(
  textAreaInput("code", "Matrizen erstellen", value = "x &lt;- c(1, 2, 3, 4, 5, 6)\n\nX &lt;- matrix(data = x, nrow = 2, ncol = 3, byrow = TRUE)\nX\n\nX &lt;- matrix(data = x, nrow = 2, ncol = 3, byrow = FALSE)\nX", width = '100%', height = '155px'),
  actionButton("run", "Run Code", class = "btn-success"),
  verbatimTextOutput("out")
)
server &lt;- function(input, output) {
  observeEvent(input$run, {
